### **Étape 1 : Configurer les Routes dans React**

Dans votre fichier `App.js`, assurez-vous que la route `/` correspond à votre composant `IndexPage` :

#### Exemple de `App.js` :
```jsx
import React, { useEffect, useState } from 'react';
import { BrowserRouter as Router, Route, Routes } from 'react-router-dom';
import IndexPage from './pages/IndexPage'; // Assurez-vous que ce fichier affiche votre index.html
import AdminPage from './pages/AdminPage';
import HomePage from './pages/HomePage';
import Page from './pages/Page';

function App() {
  const [isDbInitialized, setIsDbInitialized] = useState(false);
  const [errorMessage, setErrorMessage] = useState(null);

  useEffect(() => {
    const initializeDatabase = async () => {
      try {
        const response = await fetch('http://127.0.0.1:5000/api/init_db');
        if (!response.ok) {
          throw new Error(`Erreur HTTP : ${response.status}`);
        }
        const data = await response.json();
        console.log('Base de données initialisée:', data);
        setIsDbInitialized(true);
      } catch (error) {
        console.error("Erreur lors de l'initialisation de la base de données :", error);
        setErrorMessage("Erreur lors de l'initialisation de l'application. Veuillez vérifier le backend.");
      }
    };

    initializeDatabase();
  }, []);

  if (errorMessage) {
    return <div>{errorMessage}</div>;
  }

  if (!isDbInitialized) {
    return <div>Initialisation de l'application en cours...</div>;
  }

  return (
    <Router>
      <Routes>
        {/* Chemin vers votre composant IndexPage */}
        <Route path="/" element={<IndexPage />} />
        <Route path="/admin" element={<AdminPage />} />
        <Route path="/home" element={<HomePage />} />
        <Route path="/:pageKey" element={<Page />} />
        <Route path="*" element={<IndexPage />} />
      </Routes>
    </Router>
  );
}

export default App;
```

---

### **Étape 2 : Ajuster `IndexPage`**

Dans le fichier `IndexPage.js` (ou équivalent), vous devez importer et afficher le contenu de `index.html` :

